index c1ce364eb179..b5e06288dfcc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1516,6 +1516,7 @@ static Instruction *foldBoxMultiply(BinaryOperator &I) {
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   if (Value *V = simplifyAddInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -1847,6 +1848,29 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
         I, Builder.CreateIntrinsic(Intrinsic::ctpop, {I.getType()},
                                    {Builder.CreateOr(A, B)}));

+  // Fold ceil division pattern:
+  // (lshr X, K) + zext(and(X, (1 << K) - 1) != 0) -> lshr(X + (1 << K) - 1, K)
+  // This computes ceil(X / 2^K) as floor((X + 2^K - 1) / 2^K)
+  {
+    Value *X;
+    const APInt *K, *M;
+    Value *AndVal;
+    CmpPredicate Pred;
+    if (match(&I, m_c_Add(m_OneUse(m_LShr(m_Value(X), m_APInt(K))),
+                          m_OneUse(m_ZExt(m_OneUse(m_c_ICmp(
+                              Pred,
+                              m_Value(AndVal),
+                              m_ZeroInt())))))) &&
+        Pred == ICmpInst::ICMP_NE &&
+        match(AndVal, m_OneUse(m_And(m_Specific(X), m_APInt(M)))) &&
+        !K->isZero() && K->ult(K->getBitWidth()) &&
+        *M == ((APInt(K->getBitWidth(), 1) << *K) - 1)) {
+      Constant *C = ConstantInt::get(X->getType(), *M);
+      Value *Add = Builder.CreateAdd(X, C);
+      return BinaryOperator::CreateLShr(Add, ConstantInt::get(X->getType(), *K));
+    }
+  }
+
   // Fold the log2_ceil idiom:
   // zext(ctpop(A) >u/!= 1) + (ctlz(A, true) ^ (BW - 1))
   // -->
@@ -1893,6 +1917,7 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
   return Changed ? &I : nullptr;
 }

+
